import { createContext, useEffect, useState, useCallback } from 'react';
import { getProfile, updateProfile } from '@services/auth.service.js';
import { decodeToken, clearTokenCache } from '@helpers/jwt.helper';

export const AuthContext = createContext();

export const AuthProvider = ({ children }) => {
    const [user, setUser] = useState(null);
    const [loading, setLoading] = useState(true);
    const [userChangeFlag, setUserChangeFlag] = useState(0);

    const isTokenValid = async (token) => {
        if (!token) return false;

        try {
            const decodedToken = await decodeToken(token);
            if (!decodedToken) return false;

            const currentTime = Date.now() / 1000;
            return decodedToken.exp > currentTime;
        } catch {
            return false;
        }
    };

    const fetchUser = useCallback(async () => {
        try {
            const storedUser = localStorage.getItem('user');
            const token = localStorage.getItem('token');
            
            if (storedUser && token) {
                const tokenIsValid = await isTokenValid(token);
                
                if (tokenIsValid) {
                    setUser(JSON.parse(storedUser));
                    setLoading(false);
                    return;
                } else {
                    localStorage.removeItem('token');
                    localStorage.removeItem('user');
                }
            }
            
            if (token && await isTokenValid(token)) {
                const data = await getProfile();
                if (data) {
                    setUser(data);
                    localStorage.setItem('user', JSON.stringify(data));
                }
            } else {
                setUser(null);
            }
        } catch (error) {
            console.error('Error en fetchUser:', error);
            localStorage.removeItem('token');
            localStorage.removeItem('user');
            setUser(null);
        } finally {
            setLoading(false);
        }
    }, []);

    const refreshUser = async () => {
        setLoading(true);
        await fetchUser();
        setUserChangeFlag(prev => prev + 1);
    };

    const updateUser = async (userData) => {
        try {
            const updatedUser = await updateProfile(userData);
            setUser(updatedUser);
            localStorage.setItem('user', JSON.stringify(updatedUser));
            setUserChangeFlag(prev => prev + 1);
            return updatedUser;
        } catch (error) {
            console.error('Error al actualizar usuario:', error);
            throw error;
        }
    };

    const logout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        clearTokenCache(); 
        setUser(null);
        setUserChangeFlag(prev => prev + 1);
        
        setTimeout(() => {
            window.dispatchEvent(new CustomEvent('userChanged'));
        }, 300);
        
        window.location.href = '/OpticaDanniels';
    };

    useEffect(() => {
        fetchUser();
    }, [fetchUser]);

    return (
        <AuthContext.Provider
            value={{
                user,
                setUser,
                loading,
                isAuthenticated: !!user,
                refreshUser,
                updateUser,
                logout,
                userChangeFlag,
            }}
        >
            {children}
        </AuthContext.Provider>
    );
};

import { createContext, useContext, useReducer, useEffect } from 'react';
import { useAuth } from '@hooks/useAuth';

const CartContext = createContext();

const CART_KEY_BASE = 'optica-danniels-cart';

// Tipos de acciones
const CART_ACTIONS = {
    LOAD_CART: 'LOAD_CART',
    ADD_ITEM: 'ADD_ITEM',
    REMOVE_ITEM: 'REMOVE_ITEM',
    UPDATE_QUANTITY: 'UPDATE_QUANTITY',
    CLEAR_CART: 'CLEAR_CART'
};

// Reducer del carrito - Patrón usado por sitios exitosos
const cartReducer = (state, action) => {
    switch (action.type) {
        case CART_ACTIONS.LOAD_CART:
            return {
                ...state,
                items: action.payload.items || [],
                version: state.version + 1
            };

        case CART_ACTIONS.ADD_ITEM: {
            const existingItem = state.items.find(item => item.id === action.payload.id);
            let newItems;
            
            if (existingItem) {
                newItems = state.items.map(item =>
                    item.id === action.payload.id
                        ? { ...item, cantidad: item.cantidad + (action.payload.cantidad || 1) }
                        : item
                );
            } else {
                newItems = [...state.items, { ...action.payload, cantidad: action.payload.cantidad || 1 }];
            }

            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify(newItems));
            
            return {
                ...state,
                items: newItems,
                version: state.version + 1
            };
        }

        case CART_ACTIONS.REMOVE_ITEM: {
            const newItems = state.items.filter(item => item.id !== action.payload.productId);
            
            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify(newItems));
            
            return {
                ...state,
                items: newItems,
                version: state.version + 1
            };
        }

        case CART_ACTIONS.UPDATE_QUANTITY: {
            let newItems;
            
            if (action.payload.cantidad <= 0) {
                newItems = state.items.filter(item => item.id !== action.payload.productId);
            } else {
                newItems = state.items.map(item =>
                    item.id === action.payload.productId
                        ? { ...item, cantidad: action.payload.cantidad }
                        : item
                );
            }

            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify(newItems));
            
            return {
                ...state,
                items: newItems,
                version: state.version + 1
            };
        }

        case CART_ACTIONS.CLEAR_CART: {
            // Guardar inmediatamente en localStorage
            localStorage.setItem(action.payload.cartKey, JSON.stringify([]));
            
            return {
                ...state,
                items: [],
                version: state.version + 1
            };
        }

        default:
            return state;
    }
};

// Provider del carrito
export const CartProvider = ({ children }) => {
    const { user, isAuthenticated } = useAuth();
    const [state, dispatch] = useReducer(cartReducer, {
        items: [],
        version: 0
    });

    // Función para obtener la clave del carrito
    const getCartKey = () => {
        const userRut = user?.rut;
        return userRut ? `${CART_KEY_BASE}-${userRut}` : `${CART_KEY_BASE}-guest`;
    };

    // Cargar carrito al cambiar usuario o al inicializar
    useEffect(() => {
        const cartKey = getCartKey();
        const savedCart = localStorage.getItem(cartKey);
        
        if (savedCart) {
            try {
                const items = JSON.parse(savedCart);
                dispatch({
                    type: CART_ACTIONS.LOAD_CART,
                    payload: { items }
                });
            } catch (error) {
                console.error('Error loading cart:', error);
                localStorage.setItem(cartKey, JSON.stringify([]));
            }
        }
    }, [user?.rut, isAuthenticated]);

    // Funciones del carrito
    const addToCart = (producto, cantidad = 1) => {
        dispatch({
            type: CART_ACTIONS.ADD_ITEM,
            payload: { ...producto, cantidad, cartKey: getCartKey() }
        });
    };

    const removeFromCart = (productId) => {
        dispatch({
            type: CART_ACTIONS.REMOVE_ITEM,
            payload: { productId, cartKey: getCartKey() }
        });
    };

    const updateQuantity = (productId, cantidad) => {
        dispatch({
            type: CART_ACTIONS.UPDATE_QUANTITY,
            payload: { productId, cantidad, cartKey: getCartKey() }
        });
    };

    const clearCart = () => {
        dispatch({
            type: CART_ACTIONS.CLEAR_CART,
            payload: { cartKey: getCartKey() }
        });
    };

    // Funciones de utilidad
    const isInCart = (productId) => {
        return state.items.some(item => item.id === productId);
    };

    const getItemQuantity = (productId) => {
        const item = state.items.find(item => item.id === productId);
        return item ? item.cantidad : 0;
    };

    const getTotalPrice = () => {
        return state.items.reduce((total, item) => total + (item.precio * item.cantidad), 0);
    };

    const getTotalItems = () => {
        return state.items.reduce((total, item) => total + item.cantidad, 0);
    };

    const value = {
        // Estado
        cart: state.items,
        cartVersion: state.version, // Para forzar re-renders
        
        // Funciones
        addToCart,
        removeFromCart,
        updateQuantity,
        clearCart,
        isInCart,
        getItemQuantity,
        getTotalPrice,
        getTotalItems,
        
        // Métricas
        cartCount: state.items.length,
        totalItems: getTotalItems()
    };

    return (
        <CartContext.Provider value={value}>
            {children}
        </CartContext.Provider>
    );
};

// Hook personalizado para usar el carrito
export const useCart = () => {
    const context = useContext(CartContext);
    if (!context) {
        throw new Error('useCart debe ser usado dentro de CartProvider');
    }
    return context;
};

export default CartContext;

import React, { createContext, useContext } from 'react';
import { useWishlist } from '../hooks/useWishlist';

export const WishlistContext = createContext();

export const useWishlistContext = () => {
    const context = useContext(WishlistContext);
    if (!context) {
        throw new Error('useWishlistContext debe usarse dentro de WishlistProvider');
    }
    return context;
};

export const WishlistProvider = ({ children }) => {
    const wishlistHook = useWishlist();

    return (
        <WishlistContext.Provider value={wishlistHook}>
            {children}
        </WishlistContext.Provider>
    );
};

import { useState, useEffect, useCallback, useRef } from 'react';
import { useAuth } from './useAuth';
import { getAllProductos } from '../services/producto.service';

const WISHLIST_KEY_BASE = 'optica-danniels-wishlist';

export const useWishlist = () => {
    const [wishlist, setWishlist] = useState([]);
    const { user, loading, isAuthenticated, userChangeFlag } = useAuth();
    const previousUserRef = useRef(undefined);
    const isInitialized = useRef(false);
    const justLoaded = useRef(false);

    const getWishlistKey = useCallback(() => {
        const userRut = user?.rut;
        if (userRut) {
            return `${WISHLIST_KEY_BASE}-${userRut}`;
        }
        return `${WISHLIST_KEY_BASE}-guest`;
    }, [user?.rut]);

    const forceReloadWishlist = useCallback(() => {
        const currentUserRut = user?.rut || null;
        const wishlistKey = currentUserRut ? `${WISHLIST_KEY_BASE}-${currentUserRut}` : `${WISHLIST_KEY_BASE}-guest`;
        const savedWishlist = localStorage.getItem(wishlistKey);
        
        if (savedWishlist && savedWishlist !== '[]') {
            try {
                const parsedWishlist = JSON.parse(savedWishlist);
                setWishlist(parsedWishlist);
            } catch {
                setWishlist([]);
            }
        } else {
            setWishlist([]);
        }
        
        isInitialized.current = true;
        justLoaded.current = true;
        
        setTimeout(() => {
            justLoaded.current = false;
        }, 100);
    }, [user]);

    const validateWishlistProducts = useCallback(async () => {
        if (wishlist.length === 0) return;
        
        try {
            const response = await getAllProductos();
            const allProducts = response.productos || [];
            const existingProductIds = new Set(allProducts.map(p => p.id));
            
            const validWishlist = wishlist.filter(item => existingProductIds.has(item.id));
            
            if (validWishlist.length !== wishlist.length) {
                console.log(`Removiendo ${wishlist.length - validWishlist.length} productos eliminados de favoritos`);
                setWishlist(validWishlist);
                
                const wishlistKey = getWishlistKey();
                localStorage.setItem(wishlistKey, JSON.stringify(validWishlist));
            }
        } catch (error) {
            console.error('Error validando productos en wishlist:', error);
        }
    }, [wishlist, getWishlistKey]);

    
    useEffect(() => {
        if (wishlist.length > 0 && isInitialized.current && !justLoaded.current) {
            validateWishlistProducts();
        }
    }, [wishlist.length, validateWishlistProducts]);

    useEffect(() => {
        if (wishlist.length > 0) {
            validateWishlistProducts();
        }
    }, [validateWishlistProducts]);

    useEffect(() => {
        if (loading) return;
        
        const currentUserRut = user?.rut || null;
        const previousUserRut = previousUserRef.current;

        const userChanged = currentUserRut !== previousUserRut;
        const shouldLoad = !isInitialized.current || userChanged;
        
        if (shouldLoad) {
            previousUserRef.current = currentUserRut;
            
            forceReloadWishlist();
        }
    }, [user?.rut, user, isAuthenticated, userChangeFlag, forceReloadWishlist, loading]);

    useEffect(() => {
        const handleUserChanged = () => {
            setTimeout(() => {
                forceReloadWishlist();
            }, 50);
        };

        window.addEventListener('userChanged', handleUserChanged);
        return () => window.removeEventListener('userChanged', handleUserChanged);
    }, [forceReloadWishlist]);

    useEffect(() => {
        const handleProductoEliminado = (event) => {
            const { productoId } = event.detail;
            setWishlist(prev => {
                const newWishlist = prev.filter(item => item.id !== productoId);
                const wishlistKey = getWishlistKey();
                localStorage.setItem(wishlistKey, JSON.stringify(newWishlist));
                return newWishlist;
            });
        };

        window.addEventListener('productoEliminado', handleProductoEliminado);
        return () => window.removeEventListener('productoEliminado', handleProductoEliminado);
    }, [getWishlistKey]);

    useEffect(() => {
        if (userChangeFlag > 0) {
            setTimeout(() => {
                forceReloadWishlist();
            }, 100);
        }
    }, [userChangeFlag, forceReloadWishlist]);

    useEffect(() => {
        if (loading || !isInitialized.current || justLoaded.current) {
            return;
        }
        
        const wishlistKey = getWishlistKey();
        localStorage.setItem(wishlistKey, JSON.stringify(wishlist));
    }, [wishlist, getWishlistKey, loading]);

    const addToWishlist = useCallback((producto) => {
        setWishlist(prev => {
            if (!prev.some(item => item.id === producto.id)) {
                return [...prev, producto];
            }
            return prev;
        });
    }, []);

    const removeFromWishlist = useCallback((productoId) => {
        setWishlist(prev => prev.filter(item => item.id !== productoId));
    }, []);

    const toggleWishlist = useCallback((producto) => {
        if (wishlist.some(item => item.id === producto.id)) {
            removeFromWishlist(producto.id);
        } else {
            addToWishlist(producto);
        }
    }, [wishlist, addToWishlist, removeFromWishlist]);

    const isInWishlist = useCallback((productoId) => {
        return wishlist.some(item => item.id === productoId);
    }, [wishlist]);

    const clearWishlist = useCallback(() => {
        setWishlist([]);
    }, []);

    return {
        wishlist,
        addToWishlist,
        removeFromWishlist,
        toggleWishlist,
        isInWishlist,
        clearWishlist,
        forceReloadWishlist,
        validateWishlistProducts,
        wishlistCount: wishlist.length
    };
};

import { useParams, useNavigate } from "react-router-dom";
import { useEffect, useState } from "react";
import { getProductos } from "@services/producto.service";
import { formatearNombreParaURL } from "@helpers/formatData";
import {
    FaArrowLeft, FaShoppingCart, FaHeart, FaShare, FaFire,
    FaTag, FaShieldAlt, FaTruck, FaUndo, FaStar, FaCheck,
    FaPlus, FaMinus, FaEye, FaSpinner
} from "react-icons/fa";
import ProductCard from "@components/ProductCard";
import CartButton from "@components/CartButton";
import LazyImage from "@components/LazyImage";
import { useWishlistContext } from "@context/WishlistContext";
import { useCart } from "@context/CartContext";
import { useAuth } from "@hooks/useAuth";
import "@styles/detalleProducto.css";
import "@styles/cartButton.css";

function DetalleProducto() {
    const { nombreProducto } = useParams();
    const navigate = useNavigate();
    const { toggleWishlist, isInWishlist } = useWishlistContext();
    const { isAuthenticated } = useAuth();
    const [producto, setProducto] = useState(null);
    const [productosRecomendados, setProductosRecomendados] = useState([]);
    const [loading, setLoading] = useState(true);
    const [cantidad, setCantidad] = useState(1);

    useEffect(() => {
        const fetchProducto = async () => {
            try {
                setLoading(true);
                const nombreBuscado = formatearNombreParaURL(decodeURIComponent(nombreProducto));
                const productos = await getProductos();
                const productoEncontrado = productos.find(
                    (p) => formatearNombreParaURL(p.nombre) === nombreBuscado
                );

                if (productoEncontrado) {
                    setProducto(productoEncontrado);

                    // Obtener productos recomendados (misma categoría, excluyendo el actual)
                    const recomendados = productos
                        .filter(p =>
                            p.categoria === productoEncontrado.categoria &&
                            p.id !== productoEncontrado.id &&
                            p.activo
                        )
                        .slice(0, 4);
                    setProductosRecomendados(recomendados);
                }
            } catch (error) {
                console.error("Error al obtener el producto:", error);
            } finally {
                setLoading(false);
            }
        };

        fetchProducto();
    }, [nombreProducto]);

    const formatPrice = (price) => {
        return `$${price.toLocaleString('es-CL', { minimumFractionDigits: 0, maximumFractionDigits: 0 })}`;
    };

    const getPrecioConDescuento = () => {
        if (producto?.oferta && producto?.descuento > 0) {
            return producto.precio * (1 - producto.descuento / 100);
        }
        return producto?.precio || 0;
    };

    const handleCantidadChange = (operacion) => {
        if (operacion === 'aumentar' && cantidad < producto.stock) {
            setCantidad(cantidad + 1);
        } else if (operacion === 'disminuir' && cantidad > 1) {
            setCantidad(cantidad - 1);
        }
    };

    const handleAddToWishlist = () => {
        if (producto) {
            toggleWishlist(producto);
        }
    };

    const handleShare = () => {
        if (navigator.share) {
            navigator.share({
                title: producto.nombre,
                text: `Mira este producto: ${producto.nombre}`,
                url: window.location.href,
            });
        }
    };

    const handleGoBack = () => {
        // Verificar si hay historial previo y si es una página válida
        if (window.history.length > 1) {
            // Intentar volver al historial anterior
            navigate(-1);
        } else {
            // Si no hay historial, ir directamente a productos
            navigate('/productos');
        }
    };

    const getStockStatus = () => {
        if (producto.stock === 0) return { text: 'Sin stock', class: 'out-of-stock', available: false };
        if (producto.stock <= 5) return { text: 'Últimas unidades', class: 'low-stock', available: true };
        return { text: 'Disponible', class: 'in-stock', available: true };
    };

    if (loading) {
        return (
            <div className="detalle-loading-container">
                <div className="detalle-loading">
                    <FaSpinner className="spinner" />
                    <h3>Cargando producto...</h3>
                    <p>Un momento por favor</p>
                </div>
            </div>
        );
    }

    if (!producto) {
        return (
            <div className="detalle-error-container">
                <div className="detalle-error">
                    <h2>Producto no encontrado</h2>
                    <p>El producto que buscas no existe o ha sido eliminado.</p>
                    <button className="btn-back" onClick={handleGoBack}>
                        <FaArrowLeft />
                        Volver a productos
                    </button>
                </div>
            </div>
        );
    }

    const stockStatus = getStockStatus();
    const precioFinal = getPrecioConDescuento();

    return (
        <div className="detalle-producto-modern">
            {/* Header con navegación */}
            <div className="detalle-header-modern">
                <button className="btn-back-modern" onClick={handleGoBack}>
                    <FaArrowLeft />
                    <span>Volver</span>
                </button>
                <div className="header-actions">
                    <button className="action-icon" onClick={handleShare}>
                        <FaShare />
                    </button>
                </div>
            </div>

            {/* Contenido principal */}
            <div className="detalle-main-content">
                {/* Galería de imágenes */}
                <div className="producto-gallery">
                    <div className="main-image">
                        <LazyImage
                            src={producto.imagen_url}
                            alt={producto.nombre}
                            className="product-main-image"
                            placeholder={
                                <div className="image-placeholder-large">
                                    <FaTag />
                                </div>
                            }
                        />
                        {producto.oferta && (
                            <div className="discount-badge-large">
                                <FaFire />
                                <span>-{producto.descuento}%</span>
                            </div>
                        )}
                    </div>
                </div>

                {/* Información del producto */}
                <div className="producto-info-modern">
                    <div className="producto-header-info">
                        <div className="brand-category">
                            <span className="producto-brand">{producto.marca}</span>
                            <span className="producto-category">
                                <FaTag />
                                {producto.categoria}
                            </span>
                        </div>
                        <h1 className="producto-title">{producto.nombre}</h1>

                        {/* Rating simulado */}
                        <div className="producto-rating">
                            <div className="stars">
                                <FaStar className="star active" />
                                <FaStar className="star active" />
                                <FaStar className="star active" />
                                <FaStar className="star active" />
                                <FaStar className="star" />
                            </div>
                            <span className="rating-text">(4.2) • 127 reseñas</span>
                        </div>
                    </div>

                    {/* Precios */}
                    <div className="producto-pricing-modern">
                        {producto.oferta ? (
                            <div className="pricing-with-discount">
                                <span className="precio-original">{formatPrice(producto.precio)}</span>
                                <span className="precio-descuento">{formatPrice(precioFinal)}</span>
                                <span className="ahorro">Ahorras {formatPrice(producto.precio - precioFinal)}</span>
                            </div>
                        ) : (
                            <span className="precio-regular">{formatPrice(producto.precio)}</span>
                        )}
                    </div>

                    {/* Estado de stock */}
                    <div className={`stock-status-modern ${stockStatus.class}`}>
                        <FaCheck />
                        <span>{stockStatus.text}</span>
                        {stockStatus.available && <span className="stock-count">({producto.stock} disponibles)</span>}
                    </div>

                    {/* Descripción */}
                    <div className="producto-description-modern">
                        <h3>Descripción</h3>
                        <p>{producto.descripcion}</p>
                    </div>

                    {/* Selector de cantidad y botones */}
                    {stockStatus.available && (
                        <div className="producto-actions-section">
                            <div className="cantidad-selector">
                                <label>Cantidad:</label>
                                <div className="cantidad-controls">
                                    <button
                                        className="cantidad-btn"
                                        onClick={() => handleCantidadChange('disminuir')}
                                        disabled={cantidad <= 1}
                                    >
                                        <FaMinus />
                                    </button>
                                    <span className="cantidad-display">{cantidad}</span>
                                    <button
                                        className="cantidad-btn"
                                        onClick={() => handleCantidadChange('aumentar')}
                                        disabled={cantidad >= producto.stock}
                                    >
                                        <FaPlus />
                                    </button>
                                </div>
                            </div>

                            <div className="action-buttons">
                                <CartButton
                                    producto={producto}
                                    size="large"
                                    showQuantity={false}
                                    className="btn-add-cart"
                                />
                                {isAuthenticated && (
                                    <button
                                        className={`btn-wishlist ${producto && isInWishlist(producto.id) ? 'active' : ''}`}
                                        onClick={handleAddToWishlist}
                                    >
                                        <FaHeart />
                                    </button>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Beneficios */}
                    <div className="producto-benefits">
                        <div className="benefit-item">
                            <FaShieldAlt />
                            <span>Garantía de 1 año</span>
                        </div>
                        <div className="benefit-item">
                            <FaTruck />
                            <span>Envío gratis en Región del Biobío</span>
                        </div>
                        <div className="benefit-item">
                            <FaUndo />
                            <span>Devolución hasta 30 días</span>
                        </div>
                    </div>
                </div>
            </div>

            {/* Productos recomendados */}
            {productosRecomendados.length > 0 && (
                <div className="productos-recomendados-section">
                    <div className="recomendados-header">
                        <h2>También te puede interesar</h2>
                        <p>Productos similares en {producto.categoria}</p>
                    </div>
                    <div className="recomendados-grid">
                        {productosRecomendados.map((prod) => (
                            <ProductCard
                                key={prod.id}
                                producto={prod}
                                viewMode="grid"
                            />
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
}

